SELECT , c.name AS category_name
FROM ai_skill s
LEFT JOIN ai_skill_category c ON s.category_id = c.id

    AND s.category_id = #{categoryId}
    AND s.skill_type = #{skillType}
    AND s.status = #{status}

        AND (s.name LIKE CONCAT('%', #{keyword}, '%') OR s.code LIKE CONCAT('%', #{keyword}, '%'))


ORDER BY sort_order ASC, created_at DESC

mapper.update:
UPDATE ai_skill
category_id = #{categoryId}, name = #{name}, code = #{code}, icon = #{icon}, description = #{description}, skill_type = #{skillType}, endpoint = #{endpoint}, timeout_ms = #{timeoutMs}, input_schema = #{inputSchema}, status = #{status}, sort_order = #{sortOrder}, version = #{version},
WHERE id = #{id}
